import os
import json
import pymysql
from pymysql.cursors import DictCursor
from google.cloud import secretmanager


def get_db_password():
    """Retrieve database password from Secret Manager."""
    client = secretmanager.SecretManagerServiceClient()
    project_id = os.environ.get("GCP_PROJECT")
    secret_name = os.environ.get("DB_PASSWORD_SECRET", "cloud-sql-db-password")
    name = f"projects/{project_id}/secrets/{secret_name}/versions/latest"
    response = client.access_secret_version(request={"name": name})
    return response.payload.data.decode("UTF-8")


def get_connection():
    """Create a database connection to Cloud SQL MySQL."""
    db_user = os.environ.get("DB_USER", "app_user")
    db_name = os.environ.get("DB_NAME", "search_db")
    db_host = os.environ.get("DB_HOST", "127.0.0.1")
    db_port = int(os.environ.get("DB_PORT", "3306"))
    db_password = get_db_password()

    # For Cloud SQL with Unix socket (preferred in Cloud Functions)
    unix_socket = os.environ.get("DB_SOCKET_PATH")

    connect_args = {
        "user": db_user,
        "password": db_password,
        "database": db_name,
        "cursorclass": DictCursor,
        "charset": "utf8mb4",
        "connect_timeout": 10,
    }

    if unix_socket:
        connect_args["unix_socket"] = unix_socket
    else:
        connect_args["host"] = db_host
        connect_args["port"] = db_port

    return pymysql.connect(**connect_args)


# Whitelist of allowed tables and their searchable columns
# This prevents attackers from querying arbitrary tables/columns
ALLOWED_SCHEMAS = {
    "products": {
        "columns": ["id", "name", "category", "price", "description", "status", "created_at"],
        "sortable": ["id", "name", "price", "created_at"],
        "default_sort": "id",
    },
    "customers": {
        "columns": ["id", "first_name", "last_name", "email", "city", "state", "created_at"],
        "sortable": ["id", "first_name", "last_name", "email", "created_at"],
        "default_sort": "id",
    },
    "orders": {
        "columns": ["id", "customer_id", "status", "total_amount", "order_date"],
        "sortable": ["id", "total_amount", "order_date"],
        "default_sort": "order_date",
    },
}

# Whitelist of allowed filter operators
ALLOWED_OPERATORS = {
    "eq": "=",
    "neq": "!=",
    "gt": ">",
    "gte": ">=",
    "lt": "<",
    "lte": "<=",
    "like": "LIKE",
    "in": "IN",
    "is_null": "IS NULL",
    "is_not_null": "IS NOT NULL",
}

MAX_LIMIT = 500
DEFAULT_LIMIT = 50


def build_safe_query(table, filters, sort_by, sort_order, limit, offset, select_columns):
    """
    Build a dynamic SQL query using parameterized placeholders.

    SECURITY APPROACH:
    - Table and column names are validated against a strict whitelist
      (they cannot be parameterized in MySQL, so whitelist validation is essential)
    - All user-provided VALUES use %s parameterized placeholders
    - Operators are validated against a whitelist and never taken from user input directly
    """

    schema = ALLOWED_SCHEMAS.get(table)
    if not schema:
        raise ValueError(f"Table '{table}' is not allowed. Allowed tables: {list(ALLOWED_SCHEMAS.keys())}")

    # Validate and sanitize selected columns against whitelist
    if select_columns:
        validated_columns = []
        for col in select_columns:
            col = col.strip()
            if col in schema["columns"]:
                validated_columns.append(col)
            else:
                raise ValueError(
                    f"Column '{col}' is not allowed for table '{table}'. "
                    f"Allowed: {schema['columns']}"
                )
        columns_clause = ", ".join(f"`{col}`" for col in validated_columns)
    else:
        columns_clause = ", ".join(f"`{col}`" for col in schema["columns"])

    # Table name is from whitelist, safe to embed directly
    query = f"SELECT {columns_clause} FROM `{table}`"
    params = []

    # Build WHERE clause with parameterized values
    where_clauses = []
    if filters:
        for filter_item in filters:
            column = filter_item.get("column")
            operator_key = filter_item.get("operator", "eq")
            value = filter_item.get("value")

            # Validate column against whitelist
            if column not in schema["columns"]:
                raise ValueError(
                    f"Filter column '{column}' is not allowed for table '{table}'. "
                    f"Allowed: {schema['columns']}"
                )

            # Validate operator against whitelist
            if operator_key not in ALLOWED_OPERATORS:
                raise ValueError(
                    f"Operator '{operator_key}' is not allowed. "
                    f"Allowed: {list(ALLOWED_OPERATORS.keys())}"
                )

            sql_operator = ALLOWED_OPERATORS[operator_key]

            # Handle different operator types
            if operator_key in ("is_null", "is_not_null"):
                where_clauses.append(f"`{column}` {sql_operator}")

            elif operator_key == "in":
                if not isinstance(value, list) or len(value) == 0:
                    raise ValueError(f"'in' operator requires a non-empty list value for column '{column}'")
                if len(value) > 100:
                    raise ValueError(f"'in' operator limited to 100 values, got {len(value)}")
                placeholders = ", ".join(["%s"] * len(value))
                where_clauses.append(f"`{column}` IN ({placeholders})")
                params.extend(value)

            elif operator_key == "like":
                # User provides the pattern; we use parameterized query
                # Example value: "%search_term%"
                if not isinstance(value, str):
                    raise ValueError(f"'like' operator requires a string value for column '{column}'")
                where_clauses.append(f"`{column}` LIKE %s")
                params.append(value)

            else:
                # Standard comparison operators: eq, neq, gt, gte, lt, lte
                where_clauses.append(f"`{column}` {sql_operator} %s")
                params.append(value)

    if where_clauses:
        query += " WHERE " + " AND ".join(where_clauses)

    # Validate sort column against whitelist
    if sort_by:
        if sort_by not in schema["sortable"]:
            raise ValueError(
                f"Sort column '{sort_by}' is not allowed for table '{table}'. "
                f"Allowed: {schema['sortable']}"
            )
    else:
        sort_by = schema["default_sort"]

    # Sort order is validated to only allow two literal values
    if sort_order not in ("ASC", "DESC"):
        sort_order = "ASC"

    query += f" ORDER BY `{sort_by}` {sort_order}"

    # Limit and offset use parameterized values
    query += " LIMIT %s OFFSET %s"
    params.extend([limit, offset])

    return query, params


def build_count_query(table, filters):
    """Build a COUNT query for pagination metadata."""
    schema = ALLOWED_SCHEMAS.get(table)
    if not schema:
        raise ValueError(f"Table '{table}' is not allowed.")

    query = f"SELECT COUNT(*) as total FROM `{table}`"
    params = []

    # Reuse the same safe filter logic
    where_clauses = []
    if filters:
        for filter_item in filters:
            column = filter_item.get("column")
            operator_key = filter_item.get("operator", "eq")
            value = filter_item.get("value")

            if column not in schema["columns"]:
                raise ValueError(f"Filter column '{column}' is not allowed.")
            if operator_key not in ALLOWED_OPERATORS:
                raise ValueError(f"Operator '{operator_key}' is not allowed.")

            sql_operator = ALLOWED_OPERATORS[operator_key]

            if operator_key in ("is_null", "is_not_null"):
                where_clauses.append(f"`{column}` {sql_operator}")
            elif operator_key == "in":
                if not isinstance(value, list) or len(value) == 0:
                    raise ValueError(f"'in' operator requires a non-empty list.")
                placeholders = ", ".join(["%s"] * len(value))
                where_clauses.append(f"`{column}` IN ({placeholders})")
                params.extend(value)
            elif operator_key == "like":
                where_clauses.append(f"`{column}` LIKE %s")
                params.append(value)
            else:
                where_clauses.append(f"`{column}` {sql_operator} %s")
                params.append(value)

    if where_clauses:
        query += " WHERE " + " AND ".join(where_clauses)

    return query, params


def parse_request(request):
    """
    Parse and validate the incoming HTTP request.

    Supports both JSON body and query parameters.

    JSON body example:
    {
        "table": "products",
        "filters": [
            {"column": "category", "operator": "eq", "value": "electronics"},
            {"column": "price", "operator": "lte", "value": 999.99},
            {"column": "name", "operator": "like", "value": "%phone%"},
            {"column": "status", "operator": "in", "value": ["active", "sale"]}
        ],
        "select": ["id", "name", "price", "category"],
        "sort_by": "price",
        "sort_order": "DESC",
        "limit": 20,
        "offset": 0,
        "include_count": true
    }

    Query parameter example:
    ?table=products&category=electronics&price_lte=999.99&sort_by=price&sort_order=DESC&limit=20
    """

    content_type = request.content_type or ""

    if "application/json" in content_type:
        try:
            data = request.get_json(silent=True) or {}
        except Exception:
            raise ValueError("Invalid JSON body")
    else:
        data = {}

    # Determine table
    table = data.get("table") or request.args.get("table")
    if not table:
        raise ValueError("'table' parameter is required.")

    # Parse filters
    filters = []
    if "filters" in data and isinstance(data["filters"], list):
        filters = data["filters"]
    else:
        # Build filters from query parameters for simple GET requests
        # Format: column_operator=value (e.g., price_gte=100, name_like=%phone%)
        if request.args:
            reserved_params = {"table", "sort_by", "sort_order", "limit", "offset",
                               "select", "include_count"}
            schema = ALLOWED_SCHEMAS.get(table, {})
            allowed_cols = schema.get("columns", [])

            for param_key, param_value in request.args.items():
                if param_key in reserved_params:
                    continue

                # Parse column_operator format
                parts = param_key.rsplit("_", 1)
                if len(parts) == 2 and parts[1] in ALLOWED_OPERATORS:
                    col, op = parts
                else:
                    col = param_key
                    op = "eq"

                if col in allowed_cols:
                    # Try to parse numeric values
                    parsed_value = param_value
                    try:
                        if "." in param_value:
                            parsed_value = float(param_value)
                        else:
                            parsed_value = int(param_value)
                    except (ValueError, TypeError):
                        pass

                    filters.append({
                        "column": col,
                        "operator": op,
                        "value": parsed_value,
                    })

    # Parse other parameters
    select_columns = data.get("select") or (
        request.args.get("select", "").split(",") if request.args.get("select") else None
    )
    if select_columns:
        select_columns = [c.strip() for c in select_columns if c.strip()]

    sort_by = data.get("sort_by") or request.args.get("sort_by")
    sort_order = (data.get("sort_order") or request.args.get("sort_order", "ASC")).upper()

    limit = data.get("limit") or request.args.get("limit", DEFAULT_LIMIT)
    try:
        limit = min(int(limit), MAX_LIMIT)
    except (ValueError, TypeError):
        limit = DEFAULT_LIMIT

    offset = data.get("offset") or request.args.get("offset", 0)
    try:
        offset = max(int(offset), 0)
    except (ValueError, TypeError):
        offset = 0

    include_count = data.get("include_count", True)
    if isinstance(include_count, str):
        include_count = include_count.lower() in ("true", "1", "yes")

    return {
        "table": table,
        "filters": filters,
        "select_columns": select_columns,
        "sort_by": sort_by,
        "sort_order": sort_order,
        "limit": limit,
        "offset": offset,
        "include_count": include_count,
    }


def json_serializer(obj):
    """Custom JSON serializer for types not serializable by default."""
    import datetime
    import decimal
    if isinstance(obj, (datetime.date, datetime.datetime)):
        return obj.isoformat()
    if isinstance(obj, decimal.Decimal):
        return float(obj)
    if isinstance(obj, bytes):
        return obj.decode("utf-8", errors="replace")
    raise TypeError(f"Type {type(obj)} not serializable")


def search_api(request):
    """
    HTTP Cloud Function entry point for the search API.

    Builds dynamic, parameterized SQL queries from request parameters.
    All user values are passed as parameters (%s placeholders) to prevent SQL injection.
    Table and column names are validated against a strict whitelist.
    """

    # Handle CORS preflight
    if request.method == "OPTIONS":
        headers = {
            "Access-Control-Allow-Origin": "*",
            "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
            "Access-Control-Allow-Headers": "Content-Type, Authorization",
            "Access-Control-Max-Age": "3600",
        }
        return ("", 204, headers)

    response_headers = {
        "Access-Control-Allow-Origin": "*",
        "Content-Type": "application/json",
    }

    try:
        # Parse and validate request
        params = parse_request(request)

        # Build parameterized queries (safe from SQL injection)
        query, query_params = build_safe_query(
            table=params["table"],
            filters=params["filters"],
            sort_by=params["sort_by"],
            sort_order=params["sort_order"],
            limit=params["limit"],
            offset=params["offset"],
            select_columns=params["select_columns"],
        )

        connection = get_connection()

        try:
            with connection.cursor() as cursor:
                # Execute the parameterized search query
                cursor.execute(query, query_params)
                results = cursor.fetchall()

                total_count = None
                if params["include_count"]:
                    count_query, count_params = build_count_query(
                        table=params["table"],
                        filters=params["filters"],
                    )
                    cursor.execute(count_query, count_params)
                    count_result = cursor.fetchone()
                    total_count = count_result["total"] if count_result else 0

        finally:
            connection.close()

        # Build response
        response_body = {
            "success": True,
            "data": results,
            "pagination": {
                "limit": params["limit"],
                "offset": params["offset"],
                "returned": len(results),
            },
        }

        if total_count is not None:
            response_body["pagination"]["total"] = total_count
            response_body["pagination"]["has_more"] = (
                params["offset"] + len(results) < total_count
            )

        return (
            json.dumps(response_body, default=json_serializer),
            200,
            response_headers,
        )

    except ValueError as e:
        error_response = {
            "success": False,
            "error": "Bad Request",
            "message": str(e),
        }
        return (json.dumps(error_response), 400, response_headers)

    except pymysql.OperationalError as e:
        error_response = {
            "success": False,
            "error": "Database Connection Error",
            "message": "Unable to connect to the database. Please try again later.",
        }
        # Log the actual error for debugging (visible in Cloud Logging)
        print(f"Database operational error: {e}")
        return (json.dumps(error_response), 503, response_headers)

    except pymysql.ProgrammingError as e:
        error_response = {
            "success": False,
            "error": "Query Error",
            "message": "An error occurred while executing the query.",
        }
        print(f"Database programming error: {e}")
        return (json.dumps(error_response), 500, response_headers)

    except Exception as e:
        error_response = {
            "success": False,
            "error": "Internal Server Error",
            "message": "An unexpected error occurred.",
        }
        print(f"Unexpected error: {type(e).__name__}: {e}")
        return (json.dumps(error_response), 500, response_headers)